class TrieNode: pass
class Solution:
    def countChildren(self, node):
        if not node: return 0
        return len(node.keys())
    def solve(self, trie):
        nodes = []
        self.dfs(trie, 0, nodes)
        return nodes
    def dfs(self, node, depth, nodes):
        if node is None: return
        children = sum(1 for i in node.keys())
        nodes.append(children)
        for key in node.keys():
            self.dfs(node[key], depth + 1, nodes)

